#include <iostream>
using namespace std;

const long long M = 1e9;

int main()
{
    long long a, b, ans = 1;
    cin >> a >> b;
    for(long long i = 1; i <= b; i++)
    {
        ans *= a;
        if(ans > M)
        {
            cout << -1;
            return 0;
        }
    }
    cout << ans;
    return 0;
}
